body {
  font-family: "Inter", sans-serif;
  font-optical-sizing: auto; /* Enables automatic glyph adjustments for better appearance at different sizes */
  text-rendering: optimizeLegibility; /* Can complement optical sizing for smoother text */
}

h1 {
  font-size: 3.5rem;
  /* font-optical-sizing: auto; - inherited from body, but can be set explicitly */
}

.small-print {
  font-size: 0.8rem;
  /* font-optical-sizing: auto; - crucial for small text clarity */
}
